 18→var readyCmd = &cobra.Command{
 19→	Use:   "ready",
 20→	Short: "Show ready work (open, no active blockers)",
 21→	Long: `Show ready work (open issues with no active blockers).
 22→
 23→Excludes in_progress, blocked, deferred, and hooked issues. This uses the
 24→GetReadyWork API which applies blocker-aware semantics to find truly claimable work.
 25→
 26→Note: 'bd list --ready' is NOT equivalent - it only filters by status=open.
 27→
 28→Use --mol to filter to a specific molecule's steps:
 29→  bd ready --mol bd-patrol   # Show ready steps within molecule
 30→
 31→Use --gated to find molecules ready for gate-resume dispatch:
 32→  bd ready --gated           # Find molecules where a gate closed
 33→
 34→This is useful for agents executing molecules to see which steps can run next.`,
 35→	Run: func(cmd *cobra.Command, args []string) {
 36→		// Handle --gated flag (gate-resume discovery)
 37→		gated, _ := cmd.Flags().GetBool("gated")
 38→		if gated {
 39→			runMolReadyGated(cmd, args)
 40→			return
 41→		}
 42→
 43→		// Handle molecule-specific ready query
 44→		molID, _ := cmd.Flags().GetString("mol")
 45→		if molID != "" {
 46→			runMoleculeReady(cmd, molID)
 47→			return
 48→		}
 49→
 50→		limit, _ := cmd.Flags().GetInt("limit")
 51→		assignee, _ := cmd.Flags().GetString("assignee")
 52→		unassigned, _ := cmd.Flags().GetBool("unassigned")
 53→		sortPolicy, _ := cmd.Flags().GetString("sort")
 54→		labels, _ := cmd.Flags().GetStringSlice("label")
 55→		labelsAny, _ := cmd.Flags().GetStringSlice("label-any")
 56→		issueType, _ := cmd.Flags().GetString("type")
 57→		issueType = utils.NormalizeIssueType(issueType) // Expand aliases (mr→merge-request, etc.)
 58→		parentID, _ := cmd.Flags().GetString("parent")
 59→		molTypeStr, _ := cmd.Flags().GetString("mol-type")
 60→		prettyFormat, _ := cmd.Flags().GetBool("pretty")
 61→		plainFormat, _ := cmd.Flags().GetBool("plain")
 62→		includeDeferred, _ := cmd.Flags().GetBool("include-deferred")
 63→		includeEphemeral, _ := cmd.Flags().GetBool("include-ephemeral")
 64→		rigOverride, _ := cmd.Flags().GetString("rig")
 65→		var molType *types.MolType
 66→		if molTypeStr != "" {
 67→			mt := types.MolType(molTypeStr)
 68→			if !mt.IsValid() {
 69→				FatalError("invalid mol-type %q (must be swarm, patrol, or work)", molTypeStr)
 70→			}
 71→			molType = &mt
 72→		}
 73→		// Use global jsonOutput set by PersistentPreRun (respects config.yaml + env vars)
 74→
 75→		// Normalize labels: trim, dedupe, remove empty
 76→		labels = utils.NormalizeLabels(labels)
 77→		labelsAny = utils.NormalizeLabels(labelsAny)
 78→
 79→		// Apply directory-aware label scoping if no labels explicitly provided (GH#541)
 80→		if len(labels) == 0 && len(labelsAny) == 0 {
 81→			if dirLabels := config.GetDirectoryLabels(); len(dirLabels) > 0 {
 82→				labelsAny = dirLabels
 83→			}
 84→		}
 85→
 86→		filter := types.WorkFilter{
 87→			Status:           "open", // Only show open issues, not in_progress (matches bd list --ready)
 88→			Type:             issueType,
 89→			Limit:            limit,
 90→			Unassigned:       unassigned,
 91→			SortPolicy:       types.SortPolicy(sortPolicy),
 92→			Labels:           labels,
 93→			LabelsAny:        labelsAny,
 94→			IncludeDeferred:  includeDeferred,  // GH#820: respect --include-deferred flag
 95→			IncludeEphemeral: includeEphemeral, // bd-i5k5x: allow ephemeral issues (e.g., merge-requests)
 96→		}
 97→		// Use Changed() to properly handle P0 (priority=0)
 98→		if cmd.Flags().Changed("priority") {
 99→			priority, _ := cmd.Flags().GetInt("priority")
100→			filter.Priority = &priority
101→		}
102→		if assignee != "" && !unassigned {
103→			filter.Assignee = &assignee
104→		}
105→		if parentID != "" {
106→			filter.ParentID = &parentID
107→		}
108→		if molType != nil {
109→			filter.MolType = molType
110→		}
111→
112→		// Metadata filters (GH#1406)
113→		metadataFieldFlags, _ := cmd.Flags().GetStringArray("metadata-field")
114→		if len(metadataFieldFlags) > 0 {
115→			filter.MetadataFields = make(map[string]string, len(metadataFieldFlags))
116→			for _, mf := range metadataFieldFlags {
117→				k, v, ok := strings.Cut(mf, "=")
118→				if !ok || k == "" {
119→					fmt.Fprintf(os.Stderr, "Error: invalid --metadata-field: expected key=value, got %q\n", mf)
120→					os.Exit(1)
121→				}
122→				if err := storage.ValidateMetadataKey(k); err != nil {
123→					fmt.Fprintf(os.Stderr, "Error: invalid --metadata-field key: %v\n", err)
124→					os.Exit(1)
125→				}
126→				filter.MetadataFields[k] = v
127→			}
128→		}
129→		hasMetadataKey, _ := cmd.Flags().GetString("has-metadata-key")
130→		if hasMetadataKey != "" {
131→			if err := storage.ValidateMetadataKey(hasMetadataKey); err != nil {
132→				fmt.Fprintf(os.Stderr, "Error: invalid --has-metadata-key: %v\n", err)
133→				os.Exit(1)
134→			}
135→			filter.HasMetadataKey = hasMetadataKey
136→		}
137→
138→		// Validate sort policy
139→		if !filter.SortPolicy.IsValid() {
140→			FatalError("invalid sort policy '%s'. Valid values: hybrid, priority, oldest", sortPolicy)
141→		}
142→		// Direct mode
143→		ctx := rootCtx
144→
145→		// Handle --rig flag: query a different rig's database
146→		activeStore := store
147→		if rigOverride != "" {
148→			rigStore, err := openStoreForRig(ctx, rigOverride)
149→			if err != nil {
150→				FatalError("%v", err)
151→			}
152→			defer func() { _ = rigStore.Close() }()
153→			activeStore = rigStore
154→		} else {
155→			// Keep ready/read behavior aligned with bd create routing decisions.
156→			// Contributor auto-routing should read from the same target repo.
157→			routedStore, routed, err := openRoutedReadStore(ctx, activeStore)
158→			if err != nil {
159→				FatalError("%v", err)
160→			}
161→			if routed {
162→				defer func() { _ = routedStore.Close() }()
163→				activeStore = routedStore
164→			}
165→		}
166→
167→		issues, err := activeStore.GetReadyWork(ctx, filter)
168→		if err != nil {
169→			FatalError("%v", err)
170→		}
171→		if jsonOutput {
172→			// Always output array, even if empty
173→			if issues == nil {
174→				issues = []*types.Issue{}
175→			}
176→			issueIDs := make([]string, len(issues))
177→			for i, issue := range issues {
178→				issueIDs[i] = issue.ID
179→			}
180→			// Best effort: display gracefully degrades with empty data
181→			labelsMap, _ := activeStore.GetLabelsForIssues(ctx, issueIDs)
182→			depCounts, _ := activeStore.GetDependencyCounts(ctx, issueIDs)
183→			allDeps, _ := activeStore.GetDependencyRecordsForIssues(ctx, issueIDs)
184→			commentCounts, _ := activeStore.GetCommentCounts(ctx, issueIDs)
185→
186→			// Populate labels and dependencies for JSON output
187→			for _, issue := range issues {
188→				issue.Labels = labelsMap[issue.ID]
189→				issue.Dependencies = allDeps[issue.ID]
190→			}
191→
192→			// Build response with counts + computed parent (consistent with bd list --json)
193→			issuesWithCounts := make([]*types.IssueWithCounts, len(issues))
194→			for i, issue := range issues {
195→				counts := depCounts[issue.ID]
196→				if counts == nil {
197→					counts = &types.DependencyCounts{DependencyCount: 0, DependentCount: 0}
198→				}
199→				// Compute parent from dependency records
200→				var parent *string
201→				for _, dep := range allDeps[issue.ID] {
202→					if dep.Type == types.DepParentChild {
203→						parent = &dep.DependsOnID
204→						break
205→					}
206→				}
207→				issuesWithCounts[i] = &types.IssueWithCounts{
208→					Issue:           issue,
209→					DependencyCount: counts.DependencyCount,
210→					DependentCount:  counts.DependentCount,
211→					CommentCount:    commentCounts[issue.ID],
212→					Parent:          parent,
213→				}
214→			}
215→			outputJSON(issuesWithCounts)
216→			return
217→		}
218→		// Show upgrade notification if needed
219→		maybeShowUpgradeNotification()
220→
221→		if len(issues) == 0 {
222→			// Check if there are any open issues at all
223→			hasOpenIssues := false
224→			if stats, statsErr := activeStore.GetStatistics(ctx); statsErr == nil {
225→				hasOpenIssues = stats.OpenIssues > 0 || stats.InProgressIssues > 0
226→			}
227→			if hasOpenIssues {
228→				fmt.Printf("\n%s No ready work found (all issues have blocking dependencies)\n\n",
229→					ui.RenderWarn("✨"))
230→			} else {
231→				fmt.Printf("\n%s No open issues\n\n", ui.RenderPass("✨"))
232→			}
233→			// Show tip even when no ready work found
234→			maybeShowTip(store)
235→			return
236→		}
237→		// Check if results were truncated by the limit
238→		totalReady := len(issues)
239→		truncated := false
240→		if filter.Limit > 0 && len(issues) == filter.Limit {
241→			// Re-query without limit to get total count
242→			countFilter := filter
243→			countFilter.Limit = 0
244→			allIssues, countErr := activeStore.GetReadyWork(ctx, countFilter)
245→			if countErr == nil && len(allIssues) > len(issues) {
246→				totalReady = len(allIssues)
247→				truncated = true
248→			}
249→		}
250→
251→		// Build parent epic map for pretty display
252→		parentEpicMap := buildParentEpicMap(ctx, activeStore, issues)
253→
254→		// Determine display mode: --plain or --pretty=false triggers plain format
255→		usePlain := plainFormat || !prettyFormat
256→		if usePlain {
257→			fmt.Printf("\n%s Ready work (%d issues with no active blockers):\n\n", ui.RenderAccent("📋"), len(issues))
258→			for i, issue := range issues {
259→				fmt.Printf("%d. [%s] [%s] %s: %s\n", i+1,
260→					ui.RenderPriority(issue.Priority),
261→					ui.RenderType(string(issue.IssueType)),
262→					ui.RenderID(issue.ID), issue.Title)
263→				if issue.EstimatedMinutes != nil {
264→					fmt.Printf("   Estimate: %d min\n", *issue.EstimatedMinutes)
265→				}
266→				if issue.Assignee != "" {
267→					fmt.Printf("   Assignee: %s\n", issue.Assignee)
268→				}
269→			}
270→			fmt.Println()
271→		} else {
272→			displayReadyList(issues, parentEpicMap)
273→		}
274→
275→		// Show truncation footer if results were limited
276→		if truncated {
277→			fmt.Printf("%s\n\n", ui.RenderMuted(fmt.Sprintf("Showing %d of %d ready issues. Use -n to show more.", len(issues), totalReady)))
278→		}
279→
280→		// Show tip after successful ready (direct mode only)
281→		maybeShowTip(store)
282→	},
283→}
284→var blockedCmd = &cobra.Command{
285→	Use:   "blocked",
286→	Short: "Show blocked issues",
287→	Run: func(cmd *cobra.Command, args []string) {
288→		// Use global jsonOutput set by PersistentPreRun (respects config.yaml + env vars)
289→		// Use factory to respect backend configuration (bd-m2jr: SQLite fallback fix)
290→		ctx := rootCtx
291→		parentID, _ := cmd.Flags().GetString("parent")
292→		var blockedFilter types.WorkFilter
293→		if parentID != "" {
294→			blockedFilter.ParentID = &parentID
295→		}
296→		blocked, err := store.GetBlockedIssues(ctx, blockedFilter)
297→		if err != nil {
298→			FatalErrorRespectJSON("%v", err)
299→		}
300→		if jsonOutput {
301→			// Always output array, even if empty
302→			if blocked == nil {
303→				blocked = []*types.BlockedIssue{}
304→			}
305→			outputJSON(blocked)
306→			return
307→		}
308→		if len(blocked) == 0 {
309→			fmt.Printf("\n%s No blocked issues\n\n", ui.RenderPass("✨"))
310→			return
311→		}
312→		fmt.Printf("\n%s Blocked issues (%d):\n\n", ui.RenderFail("🚫"), len(blocked))
313→		for _, issue := range blocked {
314→			fmt.Printf("[%s] %s: %s\n",
315→				ui.RenderPriority(issue.Priority),
316→				ui.RenderID(issue.ID), issue.Title)
317→			blockedBy := issue.BlockedBy
318→			if blockedBy == nil {
319→				blockedBy = []string{}
320→			}
321→			// Resolve external refs to show real issue info (bd-k0pfm)
322→			resolved := resolveBlockedByRefs(ctx, blockedBy)
323→			fmt.Printf("  Blocked by %d open dependencies: %v\n",
324→				issue.BlockedByCount, resolved)
325→			fmt.Println()
326→		}
327→	},
328→}
