330→// buildParentEpicMap builds a map from child issue ID to parent epic title.
331→// Only includes parents that are epics.
332→func buildParentEpicMap(ctx context.Context, s *dolt.DoltStore, issues []*types.Issue) map[string]string {
333→	if len(issues) == 0 {
334→		return nil
335→	}
336→	issueIDs := make([]string, len(issues))
337→	for i, issue := range issues {
338→		issueIDs[i] = issue.ID
339→	}
340→	allDeps, err := s.GetDependencyRecordsForIssues(ctx, issueIDs)
341→	if err != nil {
342→		return nil
343→	}
344→
345→	// Find parent-child deps where the issue is the child
346→	parentIDs := make(map[string]bool)
347→	childToParent := make(map[string]string) // childID -> parentID
348→	for issueID, deps := range allDeps {
349→		for _, dep := range deps {
350→			if dep.Type == types.DepParentChild {
351→				parentIDs[dep.DependsOnID] = true
352→				childToParent[issueID] = dep.DependsOnID
353→			}
354→		}
355→	}
356→
357→	if len(parentIDs) == 0 {
358→		return nil
359→	}
360→
361→	// Fetch parent issues and filter to epics
362→	epicTitles := make(map[string]string) // parentID -> title
363→	for parentID := range parentIDs {
364→		parent, err := s.GetIssue(ctx, parentID)
365→		if err != nil || parent == nil {
366→			continue
367→		}
368→		if parent.IssueType == "epic" {
369→			epicTitles[parentID] = parent.Title
370→		}
371→	}
372→
373→	// Build final map: childID -> epic title
374→	result := make(map[string]string)
375→	for childID, parentID := range childToParent {
376→		if title, ok := epicTitles[parentID]; ok {
377→			result[childID] = title
378→		}
379→	}
380→	return result
381→}
