383→// displayReadyList displays ready issues in pretty format with optional parent epic context
384→func displayReadyList(issues []*types.Issue, parentEpicMap map[string]string) {
385→	for _, issue := range issues {
386→		epicTitle := ""
387→		if parentEpicMap != nil {
388→			epicTitle = parentEpicMap[issue.ID]
389→		}
390→		fmt.Println(formatPrettyIssueWithContext(issue, epicTitle))
391→	}
392→
393→	// Summary footer
394→	fmt.Println()
395→	fmt.Println(strings.Repeat("-", 80))
396→	fmt.Printf("Ready: %d issues with no active blockers\n", len(issues))
397→	fmt.Println()
398→	fmt.Println("Status: ○ open  ◐ in_progress  ● blocked  ✓ closed  ❄ deferred")
399→}
