401→// runMoleculeReady shows ready steps within a specific molecule
402→func runMoleculeReady(_ *cobra.Command, molIDArg string) {
403→	ctx := rootCtx
404→
405→	// Molecule-ready requires direct store access for subgraph loading
406→	if store == nil {
407→		FatalError("no database connection")
408→	}
409→
410→	// Resolve molecule ID
411→	moleculeID, err := utils.ResolvePartialID(ctx, store, molIDArg)
412→	if err != nil {
413→		FatalError("molecule '%s' not found", molIDArg)
414→	}
415→
416→	// Load molecule subgraph
417→	subgraph, err := loadTemplateSubgraph(ctx, store, moleculeID)
418→	if err != nil {
419→		FatalError("loading molecule: %v", err)
420→	}
421→
422→	// Get parallel analysis to find ready steps
423→	analysis := analyzeMoleculeParallel(subgraph)
424→
425→	// Collect ready steps
426→	var readySteps []*MoleculeReadyStep
427→	for _, issue := range subgraph.Issues {
428→		info := analysis.Steps[issue.ID]
429→		if info != nil && info.IsReady {
430→			readySteps = append(readySteps, &MoleculeReadyStep{
431→				Issue:         issue,
432→				ParallelInfo:  info,
433→				ParallelGroup: info.ParallelGroup,
434→			})
435→		}
436→	}
437→
438→	if jsonOutput {
439→		output := MoleculeReadyOutput{
440→			MoleculeID:     moleculeID,
441→			MoleculeTitle:  subgraph.Root.Title,
442→			TotalSteps:     analysis.TotalSteps,
443→			ReadySteps:     len(readySteps),
444→			Steps:          readySteps,
445→			ParallelGroups: analysis.ParallelGroups,
446→		}
447→		outputJSON(output)
448→		return
449→	}
450→
451→	// Human-readable output
452→	fmt.Printf("\n%s Ready steps in molecule: %s\n", ui.RenderAccent("🧪"), subgraph.Root.Title)
453→	fmt.Printf("   ID: %s\n", moleculeID)
454→	fmt.Printf("   Total: %d steps, %d ready\n", analysis.TotalSteps, len(readySteps))
455→
456→	if len(readySteps) == 0 {
457→		fmt.Printf("\n%s No ready steps (all blocked or completed)\n\n", ui.RenderWarn("✨"))
458→		return
459→	}
460→
461→	// Show parallel groups if any
462→	if len(analysis.ParallelGroups) > 0 {
463→		fmt.Printf("\n%s Parallel Groups:\n", ui.RenderPass("⚡"))
464→		for groupName, members := range analysis.ParallelGroups {
465→			// Check if any members are ready
466→			readyInGroup := 0
467→			for _, id := range members {
468→				if info := analysis.Steps[id]; info != nil && info.IsReady {
469→					readyInGroup++
470→				}
471→			}
472→			if readyInGroup > 0 {
473→				fmt.Printf("   %s: %d ready\n", groupName, readyInGroup)
474→			}
475→		}
476→	}
477→
478→	fmt.Printf("\n%s Ready steps:\n\n", ui.RenderPass("📋"))
479→	for i, step := range readySteps {
480→		// Show parallel group if in one
481→		groupAnnotation := ""
482→		if step.ParallelGroup != "" {
483→			groupAnnotation = fmt.Sprintf(" [%s]", ui.RenderAccent(step.ParallelGroup))
484→		}
485→
486→		fmt.Printf("%d. [%s] [%s] %s: %s%s\n", i+1,
487→			ui.RenderPriority(step.Issue.Priority),
488→			ui.RenderType(string(step.Issue.IssueType)),
489→			ui.RenderID(step.Issue.ID),
490→			step.Issue.Title,
491→			groupAnnotation)
492→
493→		// Show what this step can parallelize with
494→		if len(step.ParallelInfo.CanParallel) > 0 {
495→			readyParallel := []string{}
496→			for _, pID := range step.ParallelInfo.CanParallel {
497→				if pInfo := analysis.Steps[pID]; pInfo != nil && pInfo.IsReady {
498→					readyParallel = append(readyParallel, pID)
499→				}
500→			}
501→			if len(readyParallel) > 0 {
502→				fmt.Printf("   Can run with: %v\n", readyParallel)
503→			}
504→		}
505→	}
506→	fmt.Println()
507→}
