509→// MoleculeReadyStep holds a ready step with its parallel info
510→type MoleculeReadyStep struct {
511→	Issue         *types.Issue  `json:"issue"`
512→	ParallelInfo  *ParallelInfo `json:"parallel_info"`
513→	ParallelGroup string        `json:"parallel_group,omitempty"`
514→}
515→
516→// MoleculeReadyOutput is the JSON output for bd ready --mol
517→type MoleculeReadyOutput struct {
518→	MoleculeID     string               `json:"molecule_id"`
519→	MoleculeTitle  string               `json:"molecule_title"`
520→	TotalSteps     int                  `json:"total_steps"`
521→	ReadySteps     int                  `json:"ready_steps"`
522→	Steps          []*MoleculeReadyStep `json:"steps"`
523→	ParallelGroups map[string][]string  `json:"parallel_groups"`
524→}
