526→func init() {
527→	readyCmd.Flags().IntP("limit", "n", 10, "Maximum issues to show")
528→	readyCmd.Flags().IntP("priority", "p", 0, "Filter by priority")
529→	readyCmd.Flags().StringP("assignee", "a", "", "Filter by assignee")
530→	readyCmd.Flags().BoolP("unassigned", "u", false, "Show only unassigned issues")
531→	readyCmd.Flags().StringP("sort", "s", "priority", "Sort policy: priority (default), hybrid, oldest")
532→	readyCmd.Flags().StringSliceP("label", "l", []string{}, "Filter by labels (AND: must have ALL). Can combine with --label-any")
533→	readyCmd.Flags().StringSlice("label-any", []string{}, "Filter by labels (OR: must have AT LEAST ONE). Can combine with --label")
534→	readyCmd.Flags().StringP("type", "t", "", "Filter by issue type (task, bug, feature, epic, decision, merge-request). Aliases: mr→merge-request, feat→feature, mol→molecule, dec/adr→decision")
535→	readyCmd.Flags().String("mol", "", "Filter to steps within a specific molecule")
536→	readyCmd.Flags().String("parent", "", "Filter to descendants of this bead/epic")
537→	readyCmd.Flags().String("mol-type", "", "Filter by molecule type: swarm, patrol, or work")
538→	readyCmd.Flags().Bool("pretty", true, "Display issues in a tree format with status/priority symbols")
539→	readyCmd.Flags().Bool("plain", false, "Display issues as a plain numbered list")
540→	readyCmd.Flags().Bool("include-deferred", false, "Include issues with future defer_until timestamps")
541→	readyCmd.Flags().Bool("include-ephemeral", false, "Include ephemeral issues (wisps) in results")
542→	readyCmd.Flags().Bool("gated", false, "Find molecules ready for gate-resume dispatch")
543→	readyCmd.Flags().String("rig", "", "Query a different rig's database (e.g., --rig gastown, --rig gt-, --rig gt)")
544→	// Metadata filtering (GH#1406)
545→	readyCmd.Flags().StringArray("metadata-field", nil, "Filter by metadata field (key=value, repeatable)")
546→	readyCmd.Flags().String("has-metadata-key", "", "Filter issues that have this metadata key set")
547→	rootCmd.AddCommand(readyCmd)
548→	blockedCmd.Flags().String("parent", "", "Filter to descendants of this bead/epic")
549→	rootCmd.AddCommand(blockedCmd)
550→}
