433→// TestReadyWorkIncludesMoleculeSteps verifies that molecule steps (issues with
434→// -mol- in their IDs) appear in GetReadyWork results when they have no active
435→// blockers. Regression test for GH#1359: the old SQLite backend filtered out
436→// issues whose IDs contained "-mol-" or "-wisp-", hiding poured molecule steps
437→// from `bd ready`. The Dolt backend should not have this filtering.
438→func TestReadyWorkIncludesMoleculeSteps(t *testing.T) {
439→	t.Parallel()
440→	tmpDir := t.TempDir()
441→	testDB := filepath.Join(tmpDir, ".beads", "beads.db")
442→	s := newTestStore(t, testDB)
443→	ctx := context.Background()
444→
445→	// Simulate a poured molecule: root epic + 3 child tasks
446→	// brainstorm has no blockers (should be ready)
447→	// specify is blocked by brainstorm
448→	// hydrate is blocked by specify
449→	molIssues := []*types.Issue{
450→		{ID: "test-mol-root", Title: "feature-workflow", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeEpic, CreatedAt: time.Now()},
451→		{ID: "test-mol-brainstorm", Title: "Brainstorm feature", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask, CreatedAt: time.Now()},
452→		{ID: "test-mol-specify", Title: "Update specifications", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask, CreatedAt: time.Now()},
453→		{ID: "test-mol-hydrate", Title: "Hydrate planning", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask, CreatedAt: time.Now()},
454→	}
455→	for _, issue := range molIssues {
456→		if err := s.CreateIssue(ctx, issue, "test"); err != nil {
457→			t.Fatal(err)
458→		}
459→	}
460→
461→	// Parent-child: all children belong to root epic
462→	parentChildDeps := []*types.Dependency{
463→		{IssueID: "test-mol-brainstorm", DependsOnID: "test-mol-root", Type: types.DepParentChild, CreatedAt: time.Now()},
464→		{IssueID: "test-mol-specify", DependsOnID: "test-mol-root", Type: types.DepParentChild, CreatedAt: time.Now()},
465→		{IssueID: "test-mol-hydrate", DependsOnID: "test-mol-root", Type: types.DepParentChild, CreatedAt: time.Now()},
466→	}
467→	for _, dep := range parentChildDeps {
468→		if err := s.AddDependency(ctx, dep, "test"); err != nil {
469→			t.Fatal(err)
470→		}
471→	}
472→
473→	// Blocking: brainstorm blocks specify, specify blocks hydrate
474→	blockDeps := []*types.Dependency{
475→		{IssueID: "test-mol-specify", DependsOnID: "test-mol-brainstorm", Type: types.DepBlocks, CreatedAt: time.Now()},
476→		{IssueID: "test-mol-hydrate", DependsOnID: "test-mol-specify", Type: types.DepBlocks, CreatedAt: time.Now()},
477→	}
478→	for _, dep := range blockDeps {
479→		if err := s.AddDependency(ctx, dep, "test"); err != nil {
480→			t.Fatal(err)
481→		}
482→	}
