105→// GetReadyWork returns issues that are ready to work on (not blocked)
106→func (s *DoltStore) GetReadyWork(ctx context.Context, filter types.WorkFilter) ([]*types.Issue, error) {
107→	s.mu.RLock()
108→	defer s.mu.RUnlock()
109→
110→	// Status filtering: default to open OR in_progress (matches memory storage)
111→	var statusClause string
112→	if filter.Status != "" {
113→		statusClause = "status = ?"
114→	} else {
115→		statusClause = "status IN ('open', 'in_progress')"
116→	}
117→	whereClauses := []string{
118→		statusClause,
119→		"(pinned = 0 OR pinned IS NULL)", // Exclude pinned issues (context markers, not work)
120→	}
121→	if !filter.IncludeEphemeral {
122→		whereClauses = append(whereClauses, "(ephemeral = 0 OR ephemeral IS NULL)")
123→	}
124→	args := []interface{}{}
125→	if filter.Status != "" {
126→		args = append(args, string(filter.Status))
127→	}
128→
129→	if filter.Priority != nil {
130→		whereClauses = append(whereClauses, "priority = ?")
131→		args = append(args, *filter.Priority)
132→	}
133→	// Use subquery for type filter to prevent Dolt mergeJoinIter panic (see SearchIssues).
134→	if filter.Type != "" {
135→		whereClauses = append(whereClauses, "id IN (SELECT id FROM issues WHERE issue_type = ?)")
136→		args = append(args, filter.Type)
137→	} else {
138→		// Exclude workflow/identity types from ready work by default.
139→		// These are internal items, not actionable work for agents to claim:
140→		// - merge-request: processed by Refinery
141→		// - gate: async wait conditions
142→		// - molecule: workflow containers
143→		// - message: mail/communication items
144→		// - agent: identity/state tracking beads
145→		// - role: agent role definitions (reference metadata)
146→		// - rig: rig identity beads (reference metadata)
147→		excludeTypes := []string{"merge-request", "gate", "molecule", "message", "agent", "role", "rig"}
148→		placeholders := make([]string, len(excludeTypes))
149→		for i, t := range excludeTypes {
150→			placeholders[i] = "?"
151→			args = append(args, t)
152→		}
153→		whereClauses = append(whereClauses, fmt.Sprintf("id IN (SELECT id FROM issues WHERE issue_type NOT IN (%s))", strings.Join(placeholders, ",")))
154→	}
155→	// Unassigned takes precedence over Assignee filter (matches memory storage)
156→	if filter.Unassigned {
157→		whereClauses = append(whereClauses, "(assignee IS NULL OR assignee = '')")
158→	} else if filter.Assignee != nil {
159→		whereClauses = append(whereClauses, "assignee = ?")
160→		args = append(args, *filter.Assignee)
161→	}
162→	// Exclude future-deferred issues unless IncludeDeferred is set
163→	if !filter.IncludeDeferred {
164→		whereClauses = append(whereClauses, "(defer_until IS NULL OR defer_until <= NOW())")
165→	}
166→	// Exclude children of future-deferred parents (GH#1190)
167→	// Pre-compute excluded IDs using separate single-table queries to avoid
168→	// correlated cross-table JOIN subquery that triggers Dolt joinIter hangs.
169→	if !filter.IncludeDeferred {
170→		deferredChildIDs, dcErr := s.getChildrenOfDeferredParents(ctx)
171→		if dcErr == nil && len(deferredChildIDs) > 0 {
172→			// Batch the NOT IN clause to avoid oversized queries (GH#2179).
173→			for start := 0; start < len(deferredChildIDs); start += queryBatchSize {
174→				end := start + queryBatchSize
175→				if end > len(deferredChildIDs) {
176→					end = len(deferredChildIDs)
177→				}
178→				placeholders, batchArgs := doltBuildSQLInClause(deferredChildIDs[start:end])
179→				args = append(args, batchArgs...)
180→				whereClauses = append(whereClauses, fmt.Sprintf("id NOT IN (%s)", placeholders))
181→			}
182→		}
183→	}
184→	if len(filter.Labels) > 0 {
185→		for _, label := range filter.Labels {
186→			whereClauses = append(whereClauses, "id IN (SELECT issue_id FROM labels WHERE label = ?)")
187→			args = append(args, label)
188→		}
189→	}
190→	// Parent filtering: filter to children of specified parent (GH#2009)
191→	// Explicit parent-child dependency takes precedence over dotted-ID prefix.
192→	if filter.ParentID != nil {
193→		parentID := *filter.ParentID
194→		whereClauses = append(whereClauses, "(id IN (SELECT issue_id FROM dependencies WHERE type = 'parent-child' AND depends_on_id = ?) OR (id LIKE CONCAT(?, '.%') AND id NOT IN (SELECT issue_id FROM dependencies WHERE type = 'parent-child')))")
195→		args = append(args, parentID, parentID)
196→	}
197→
198→	// Metadata existence check (GH#1406)
199→	if filter.HasMetadataKey != "" {
200→		if err := storage.ValidateMetadataKey(filter.HasMetadataKey); err != nil {
201→			return nil, err
202→		}
203→		whereClauses = append(whereClauses, "JSON_EXTRACT(metadata, ?) IS NOT NULL")
204→		args = append(args, "$."+filter.HasMetadataKey)
205→	}
206→
207→	// Metadata field equality filters (GH#1406)
208→	if len(filter.MetadataFields) > 0 {
209→		metaKeys := make([]string, 0, len(filter.MetadataFields))
210→		for k := range filter.MetadataFields {
211→			metaKeys = append(metaKeys, k)
212→		}
213→		sort.Strings(metaKeys)
214→		for _, k := range metaKeys {
215→			if err := storage.ValidateMetadataKey(k); err != nil {
216→				return nil, err
217→			}
218→			whereClauses = append(whereClauses, "JSON_UNQUOTE(JSON_EXTRACT(metadata, ?)) = ?")
219→			args = append(args, "$."+k, filter.MetadataFields[k])
220→		}
221→	}
222→
223→	// Exclude blocked issues: pre-compute blocked set using separate single-table
224→	// queries to avoid Dolt's joinIter panic (join_iters.go:192).
225→	// Correlated EXISTS/NOT EXISTS subqueries across tables trigger the same panic.
226→	// Skip wisp table scanning when ephemeral items aren't requested — no cross-table
227→	// blocking deps exist, and skipping 16K+ wisps avoids query timeouts.
228→	blockedIDs, err := s.computeBlockedIDs(ctx, filter.IncludeEphemeral)
229→	if err == nil && len(blockedIDs) > 0 {
230→		// Also exclude children of blocked parents (GH#1495):
231→		// If a parent/epic is blocked, its children should not appear as ready work.
232→		childrenOfBlocked, childErr := s.getChildrenOfIssues(ctx, blockedIDs)
233→		if childErr == nil {
