235→				blockedIDs = append(blockedIDs, childID)
236→			}
237→		}
238→
239→		// Batch the NOT IN clause to avoid oversized queries (GH#2179).
240→		for start := 0; start < len(blockedIDs); start += queryBatchSize {
241→			end := start + queryBatchSize
242→			if end > len(blockedIDs) {
243→				end = len(blockedIDs)
244→			}
245→			batch := blockedIDs[start:end]
246→			placeholders, batchArgs := doltBuildSQLInClause(batch)
247→			args = append(args, batchArgs...)
248→			whereClauses = append(whereClauses, fmt.Sprintf("id NOT IN (%s)", placeholders))
249→		}
250→	}
