252→	whereSQL := "WHERE " + strings.Join(whereClauses, " AND ")
253→
254→	limitSQL := ""
255→	if filter.Limit > 0 {
256→		limitSQL = fmt.Sprintf(" LIMIT %d", filter.Limit)
257→	}
258→
259→	// Build ORDER BY clause based on SortPolicy
260→	var orderBySQL string
261→	switch filter.SortPolicy {
