268→		// older issues are sorted by age (oldest first) to prevent starvation.
269→		orderBySQL = `ORDER BY
270→			CASE WHEN created_at >= DATE_SUB(NOW(), INTERVAL 48 HOUR) THEN 0 ELSE 1 END ASC,
271→			CASE WHEN created_at >= DATE_SUB(NOW(), INTERVAL 48 HOUR) THEN priority ELSE 999 END ASC,
272→			created_at ASC, id ASC`
273→	default:
274→		orderBySQL = "ORDER BY priority ASC, created_at DESC, id ASC"
275→	}
276→
277→	// nolint:gosec // G201: whereSQL contains column comparisons with ?, limitSQL is a safe integer
278→	query := fmt.Sprintf(`
279→		SELECT id FROM issues
280→		%s
281→		%s
282→		%s
283→	`, whereSQL, orderBySQL, limitSQL)
284→
285→	rows, err := s.queryContext(ctx, query, args...)
286→	if err != nil {
287→		return nil, fmt.Errorf("failed to get ready work: %w", err)
288→	}
289→	defer rows.Close()
290→
291→	issues, err := s.scanIssueIDs(ctx, rows)
292→	if err != nil {
293→		return nil, err
294→	}
295→
296→	// When IncludeEphemeral is set, also query the wisps table for ready work.
297→	if filter.IncludeEphemeral {
298→		wispFilter := types.IssueFilter{Limit: filter.Limit}
299→		if filter.Status != "" {
300→			s := filter.Status
301→			wispFilter.Status = &s
